import React, { useEffect, useState } from "react";
import axios from "axios";
import Modal from './components/Modal';
import FormAgendamento from './components/FormAgendamento';

export default function DashboardDisciplinas() {
  const [disciplinas, setDisciplinas] = useState([]);
  const [disciplinaSelecionada, setDisciplinaSelecionada] = useState(null);
  const [agendamentosFiltrados, setAgendamentosFiltrados] = useState([]);
  const [carregandoAgendamentos, setCarregandoAgendamentos] = useState(false);
  const [mostrarModal, setMostrarModal] = useState(false);
  const [agendamentoEditando, setAgendamentoEditando] = useState(null);

  // Filtros e busca
  const [busca, setBusca] = useState('');
  const [filtroData, setFiltroData] = useState('');
  const [filtroHora, setFiltroHora] = useState('');
  const [showData, setShowData] = useState(false);
  const [showHora, setShowHora] = useState(false);

  // Cores dos cards
  const cardColors = [
    "bg-[#659D9E]",
    "bg-[#7796BA]",
    "bg-[#BC8C00]",
    "bg-[#0698DC]",
    "bg-[#157779]",
    "bg-[#607287]",
    "bg-[#558B54]",
    "bg-[#40545F]",
    "bg-[#888D8D]",
    "bg-[#727198]",
    "bg-[#AD699F]"
  ];

  useEffect(() => {
    axios.get("/api/disciplinas").then(res => setDisciplinas(res.data));
  }, []);

  function buscarAgendamentosDaDisciplina(disciplina) {
    setDisciplinaSelecionada(disciplina);
    setCarregandoAgendamentos(true);
    axios.get(`/api/agendamentos?disciplinaId=${disciplina.id}`)
      .then(res => setAgendamentosFiltrados(res.data))
      .finally(() => setCarregandoAgendamentos(false));
  }

  // Filtra agendamentos conforme busca/filtros
  const agendamentosExibidos = agendamentosFiltrados.filter(ag => {
    const textoBusca = busca.toLowerCase();
    const campos = [
      ag.operadorNome,
      ag.auxiliarNome,
      ag.periodo_nome,
      ag.pacienteNome,
      ag.status
    ].map(x => x ? x.toLowerCase() : '');
    const matchTexto = campos.some(campo => campo.includes(textoBusca));
    const matchData = filtroData ? (ag.data && ag.data.startsWith(filtroData)) : true;
    const matchHora = filtroHora ? (ag.hora && ag.hora.startsWith(filtroHora)) : true;
    return matchTexto && matchData && matchHora;
  });

  function handleImprimir() {
    const conteudo = `
      <div style="background:#fff;padding:32px;">
        <h2 style="font-size:24px;font-weight:bold;margin-bottom:8px;">Agendamentos de ${disciplinaSelecionada?.nome}</h2>
        <table border="1" cellspacing="0" cellpadding="8" style="margin-top:24px;width:100%;border-collapse:collapse;font-size:16px;">
          <thead>
            <tr>
              <th>Operador</th>
              <th>Auxiliar</th>
              <th>Período</th>
              <th>Disciplina</th>
              <th>Paciente</th>
              <th>Data</th>
              <th>Hora</th>
              <th>Status</th>
            </tr>
          </thead>
          <tbody>
            ${agendamentosExibidos.map(ag => `
              <tr>
                <td>${ag.operadorNome || ''}</td>
                <td>${ag.auxiliarNome || ''}</td>
                <td>${ag.periodo_nome || ''}</td>
                <td>${disciplinaSelecionada?.nome || ''}</td>
                <td>${ag.pacienteNome || ''}</td>
                <td>${ag.data ? ag.data.slice(0, 10).split('-').reverse().join('/') : ''}</td>
                <td>${ag.hora || ''}</td>
                <td>${ag.status || ''}</td>
              </tr>
            `).join('')}
          </tbody>
        </table>
        <style>
          @media print {
            body { background: #fff !important; }
          }
        </style>
      </div>
    `;
    const win = window.open('', '', 'width=900,height=650');
    win.document.write('<html><head><title>Imprimir Lista</title></head><body>');
    win.document.write(conteudo);
    win.document.write('</body></html>');
    win.document.close();
    setTimeout(() => {
      win.print();
      win.close();
    }, 350);
  }

  function handleDeletarAgendamento(id) {
    if (window.confirm('Tem certeza que deseja deletar este agendamento?')) {
      axios.delete(`/api/agendamentos/${id}`)
        .then(() => {
          setAgendamentosFiltrados(current => current.filter(a => a.id !== id));
        })
        .catch(() => alert('Erro ao deletar agendamento'));
    }
  }
  function handleEditarAgendamento(agendamento) {
    setAgendamentoEditando(agendamento);
    setMostrarModal(true);
  }
  function handleSalvarAgendamentoEditado() {
    if (disciplinaSelecionada) {
      buscarAgendamentosDaDisciplina(disciplinaSelecionada);
    }
    setMostrarModal(false);
    setAgendamentoEditando(null);
  }
  function handleCancelarEdicao() {
    setMostrarModal(false);
    setAgendamentoEditando(null);
  }

  // ToolTip custom (mantém acima sempre)
  function Tooltip({ text }) {
    return (
      <span className="absolute left-1/2 -translate-x-1/2 -top-8 w-max bg-gray-900 text-white text-xs rounded py-1 px-2 z-50 pointer-events-none opacity-0 group-hover:opacity-100 transition">
        {text}
      </span>
    );
  }

  return (
    <div className="mx-auto py-8 px-4">
      <h1 className="text-2xl font-bold mb-6 text-[#1d3557]">Disciplinas</h1>

      {/* Cards das disciplinas */}
      <div className="flex flex-wrap gap-2 mb-8">
        {disciplinas.map((disc, idx) => (
          <button
            key={disc.id}
            className={`min-w-[200px] flex-1 rounded-2xl px-6 py-8 text-left border-2 transition
              ${disciplinaSelecionada?.id === disc.id
                ? "border-[#F3F3F3] bg-[#3172C0]"
                : `border-transparent hover:border-[#3172C0] hover:bg-[#3172C0] ${cardColors[idx % cardColors.length]}`}`}
            onClick={() => buscarAgendamentosDaDisciplina(disc)}
          >
            <div className="font-bold text-lg text-[#ffffff] mb-1">{disc.nome}</div>
            <div className="text-[#ffffff] text-sm">{disc.periodo_nome} {disc.turno}</div>
          </button>
        ))}
      </div>

      {/* Lista de agendamentos da disciplina selecionada */}
      {disciplinaSelecionada && (
        <div className="bg-white rounded-2xl shadow border">
          <h2 className="text-lg font-semibold px-6 pt-6 pb-2">
            Agendamentos de <span className="text-[#3172C0]">{disciplinaSelecionada.nome}</span>
          </h2>

          {/* Filtros (barra de pesquisa, icones) */}
          <div className="flex flex-col md:flex-row md:items-end gap-3 p-4 pt-0 pb-4 rounded-2xl bg-white mb-6">
            <div className="flex-1 relative">
              <label className="block text-sm font-medium mb-2">Pesquisar</label>
              <input
                type="text"
                className="border rounded px-4 py-2 w-full rounded-2xl"
                placeholder="Operador, Auxiliar, Período, Paciente ou Status"
                value={busca}
                onChange={e => setBusca(e.target.value)}
              />
            </div>
            {/* Ícones */}
            <div className="flex items-center gap-4 mt-4 md:mt-0 relative">
              {/* Data */}
              <div className="relative group flex items-center">
                <button
                  type="button"
                  className="p-2 hover:bg-gray-200 rounded-full transition"
                  onClick={() => setShowData(show => !show)}
                >
                  {/* calendar icon */}
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-[#3172C0]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <rect x="4" y="6" width="16" height="14" rx="2" strokeWidth="2" stroke="currentColor" fill="white"/>
                    <path d="M16 2v4M8 2v4M4 10h16" strokeWidth="2" stroke="currentColor"/>
                  </svg>
                </button>
                <Tooltip text="Filtrar por data" />
                {/* Campo de data flutuante */}
                {showData && (
                  <input
                    type="date"
                    className="absolute z-20 mt-10 left-1/2 -translate-x-1/2 bg-white border rounded px-3 py-2 shadow"
                    value={filtroData}
                    onChange={e => { setFiltroData(e.target.value); setShowData(false); }}
                    onBlur={() => setShowData(false)}
                    autoFocus
                  />
                )}
              </div>
              {/* Hora */}
              <div className="relative group flex items-center">
                <button
                  type="button"
                  className="p-2 hover:bg-gray-200 rounded-full transition"
                  onClick={() => setShowHora(show => !show)}
                >
                  {/* clock icon */}
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-[#3172C0]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <circle cx="12" cy="12" r="9" strokeWidth="2" stroke="currentColor" fill="white"/>
                    <path d="M12 7v5l3 3" strokeWidth="2" stroke="currentColor"/>
                  </svg>
                </button>
                <Tooltip text="Filtrar por hora" />
                {showHora && (
                  <input
                    type="time"
                    className="absolute z-20 mt-10 left-1/2 -translate-x-1/2 bg-white border rounded px-3 py-2 shadow"
                    value={filtroHora}
                    onChange={e => { setFiltroHora(e.target.value); setShowHora(false); }}
                    onBlur={() => setShowHora(false)}
                    autoFocus
                  />
                )}
              </div>
              {/* Imprimir */}
              <div className="relative group flex items-center">
                <button
                  type="button"
                  className="p-2 hover:bg-gray-200 rounded-full transition"
                  onClick={handleImprimir}
                >
                  {/* printer icon */}
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-[#3172C0]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <rect x="6" y="9" width="12" height="7" rx="2" strokeWidth="2" stroke="currentColor" fill="white"/>
                    <path d="M6 9V5a2 2 0 012-2h8a2 2 0 012 2v4" strokeWidth="2" stroke="currentColor"/>
                    <rect x="9" y="16" width="6" height="4" rx="1" strokeWidth="2" stroke="currentColor" fill="white"/>
                  </svg>
                </button>
                <Tooltip text="Imprimir Lista" />
              </div>
            </div>
          </div>

          <div className="overflow-x-auto">
            <div className="mt-8">
              <div className="space-y-3">
                {carregandoAgendamentos ? (
                  <div className="py-6 text-center text-gray-400 bg-gray-50 rounded-xl">
                    Carregando agendamentos...
                  </div>
                ) : agendamentosExibidos.length === 0 ? (
                  <div className="py-6 text-center text-gray-400 bg-gray-50 rounded-xl">
                    Nenhum agendamento para esta disciplina.
                  </div>
                ) : (
                  agendamentosExibidos.map((ag) => (
                    <div
                      key={ag.id}
                      className="flex flex-col md:flex-row md:items-center justify-between bg-gray-50 rounded-xl px-5 py-3 shadow-sm hover:bg-gray-100 transition"
                    >
                      <div className="flex-1 flex flex-col md:flex-row gap-2 md:gap-6">
                        <div>
                          <span className="block text-sm text-gray-500">Operador</span>
                          <span className="font-medium text-gray-800">{ag.operadorNome}</span>
                        </div>
                        <div>
                          <span className="block text-sm text-gray-500">Auxiliar</span>
                          <span className="text-gray-800">{ag.auxiliarNome}</span>
                        </div>
                        <div>
                          <span className="block text-sm text-gray-500">Período</span>
                          <span className="text-gray-800">{ag.periodo_nome}</span>
                        </div>
                        <div>
                          <span className="block text-sm text-gray-500">Disciplina</span>
                          <span className="text-gray-800">{disciplinaSelecionada?.nome}</span>
                        </div>
                        <div>
                          <span className="block text-sm text-gray-500">Paciente</span>
                          <span className="text-gray-800">{ag.pacienteNome}</span>
                        </div>
                        <div>
                          <span className="block text-sm text-gray-500">Data</span>
                          <span className="text-gray-800">
                            {ag.data ? ag.data.slice(0, 10).split('-').reverse().join('/') : ''}
                          </span>
                        </div>
                        <div>
                          <span className="block text-sm text-gray-500">Hora</span>
                          <span className="text-gray-800">{ag.hora}</span>
                        </div>
                        <div>
                          <span className="block text-sm text-gray-500">Status</span>
                          <span className="inline-block px-3 py-1 rounded-full text-xs font-semibold bg-blue-100 text-blue-700">
                            {ag.status}
                          </span>
                        </div>
                      </div>
                      <div className="flex gap-2 mt-3 md:mt-0 md:ml-4">
                        <button
                          onClick={() => handleEditarAgendamento(ag)}
                          className="px-4 py-1 rounded-lg bg-blue-100 text-blue-800 hover:bg-blue-200 font-semibold transition"
                        >
                          Editar
                        </button>
                        <button
                          onClick={() => handleDeletarAgendamento(ag.id)}
                          className="px-4 py-1 rounded-lg bg-red-100 text-red-700 hover:bg-red-200 font-semibold transition"
                        >
                          Deletar
                        </button>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>
            <Modal isOpen={mostrarModal} onRequestClose={handleCancelarEdicao}>
              <FormAgendamento
                agendamentoEditando={agendamentoEditando}
                onNovoAgendamento={handleSalvarAgendamentoEditado}
                onFimEdicao={handleCancelarEdicao}
              />
            </Modal>
          </div>
        </div>
      )}
    </div>
  );
}
